import{_ as a,o as n,c as t,a2 as e}from"./chunks/framework.CBOyQ9KN.js";const h=JSON.parse('{"title":"Cursor AI 通信协议 — 最终确定性报告","description":"","frontmatter":{},"headers":[],"relativePath":"05-communication-protocol/final-communication-protocol.md","filePath":"05-communication-protocol/final-communication-protocol.md","lastUpdated":null}'),r={name:"05-communication-protocol/final-communication-protocol.md"};function p(i,s,l,o,d,c){return n(),t("div",null,[...s[0]||(s[0]=[e(`<h1 id="cursor-ai-通信协议-—-最终确定性报告" tabindex="-1">Cursor AI 通信协议 — 最终确定性报告 <a class="header-anchor" href="#cursor-ai-通信协议-—-最终确定性报告" aria-label="Permalink to &quot;Cursor AI 通信协议 — 最终确定性报告&quot;">​</a></h1><h2 id="架构全景" tabindex="-1">架构全景 <a class="header-anchor" href="#架构全景" aria-label="Permalink to &quot;架构全景&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Cursor 客户端 ──ConnectRPC──→ api2.cursor.sh ──代理──→ LLM Provider</span></span>
<span class="line"><span>                               (baseUrl)             (Anthropic/OpenAI/etc)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><strong>模型请求不直接发到 cursorvm-manager.com</strong>。所有请求经过 <code>api2.cursor.sh</code> 的 ConnectRPC 网关。</p><hr><h2 id="_1-传输层协议" tabindex="-1">1. 传输层协议 <a class="header-anchor" href="#_1-传输层协议" aria-label="Permalink to &quot;1. 传输层协议&quot;">​</a></h2><h3 id="_1-1-connectrpc-主协议" tabindex="-1">1.1 ConnectRPC（主协议） <a class="header-anchor" href="#_1-1-connectrpc-主协议" aria-label="Permalink to &quot;1.1 ConnectRPC（主协议）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>项目</th><th>值</th></tr></thead><tbody><tr><td>协议</td><td><strong>ConnectRPC</strong>（gRPC 兼容，HTTP/1.1 + HTTP/2）</td></tr><tr><td>序列化</td><td>Protocol Buffers（二进制）</td></tr><tr><td>备用格式</td><td>SSE ServerStreaming（JSON 事件流）</td></tr><tr><td>baseUrl</td><td><code>https://api2.cursor.sh</code></td></tr><tr><td>认证</td><td><code>Authorization: Bearer {accessToken}</code></td></tr><tr><td>自定义头</td><td><code>x-ghost-mode</code>, <code>x-session-id</code>, <code>x-cursor-client-version</code> 等</td></tr></tbody></table><h3 id="_1-2-核心服务列表" tabindex="-1">1.2 核心服务列表 <a class="header-anchor" href="#_1-2-核心服务列表" aria-label="Permalink to &quot;1.2 核心服务列表&quot;">​</a></h3><table tabindex="0"><thead><tr><th>服务名</th><th>typeName</th><th style="text-align:center;">是否已验证可达</th></tr></thead><tbody><tr><td>AuthService</td><td><code>aiserver.v1.AuthService</code></td><td style="text-align:center;">✅</td></tr><tr><td>DashboardService</td><td><code>aiserver.v1.DashboardService</code></td><td style="text-align:center;">✅</td></tr><tr><td>ChatService</td><td><code>aiserver.v1.ChatService</code></td><td style="text-align:center;">⚠️ 需要 Protobuf</td></tr><tr><td>AnalyticsService</td><td><code>aiserver.v1.AnalyticsService</code></td><td style="text-align:center;">✅</td></tr><tr><td>HealthService</td><td><code>aiserver.v1.HealthService</code></td><td style="text-align:center;">❌ 404</td></tr><tr><td>AgentService</td><td><code>agent.v1.AgentService</code></td><td style="text-align:center;">❌ 404</td></tr><tr><td>AiService</td><td><code>aiserver.v1.AiService</code></td><td style="text-align:center;">⚠️ 需要 Protobuf</td></tr></tbody></table><hr><h2 id="_2-ai-对话核心协议" tabindex="-1">2. AI 对话核心协议 <a class="header-anchor" href="#_2-ai-对话核心协议" aria-label="Permalink to &quot;2. AI 对话核心协议&quot;">​</a></h2><h3 id="_2-1-最终方法" tabindex="-1">2.1 最终方法 <a class="header-anchor" href="#_2-1-最终方法" aria-label="Permalink to &quot;2.1 最终方法&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Service:  aiserver.v1.ChatService</span></span>
<span class="line"><span>Method:   StreamUnifiedChat (ServerStreaming)</span></span>
<span class="line"><span>TypeName: aiserver.v1.StreamUnifiedChatRequest</span></span>
<span class="line"><span></span></span>
<span class="line"><span>ConnectRPC URL 格式 (POST):</span></span>
<span class="line"><span>  JSON:    https://api2.cursor.sh/aiserver.v1.ChatService/StreamUnifiedChat</span></span>
<span class="line"><span>           Content-Type: application/json</span></span>
<span class="line"><span>  二进制:  https://api2.cursor.sh/aiserver.v1.ChatService/StreamUnifiedChat</span></span>
<span class="line"><span>           Content-Type: application/proto</span></span>
<span class="line"><span>  SSE:     https://api2.cursor.sh/aiserver.v1.ChatService/StreamUnifiedChat</span></span>
<span class="line"><span>           Content-Type: application/json</span></span>
<span class="line"><span>           Accept: text/event-stream</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><h3 id="_2-2-streamunifiedchatrequest-字段列表-从-protobuf-定义提取" tabindex="-1">2.2 StreamUnifiedChatRequest 字段列表（从 Protobuf 定义提取） <a class="header-anchor" href="#_2-2-streamunifiedchatrequest-字段列表-从-protobuf-定义提取" aria-label="Permalink to &quot;2.2 StreamUnifiedChatRequest 字段列表（从 Protobuf 定义提取）&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>  &quot;conversation&quot;:</span><span>              // 对话历史</span></span>
<span class="line"><span>  &quot;model&quot;:</span><span>                     // 模型参数</span></span>
<span class="line"><span>  &quot;mode&quot;:</span><span>                      // 模式: CHAT / AGENT / EDIT / PLAN / DEBUG</span></span>
<span class="line"><span>  &quot;thinking_level&quot;:</span><span>            // 思考级别</span></span>
<span class="line"><span>  &quot;selected_context&quot;:</span><span>          // 附加上下文（文件、终端等）</span></span>
<span class="line"><span>  &quot;hooks_config&quot;:</span><span>              // Hook 配置</span></span>
<span class="line"><span>  &quot;conversation_state&quot;:</span><span>        // 对话状态（序列化）</span></span>
<span class="line"><span>  &quot;metadata&quot;:</span><span>                  // 元数据</span></span>
<span class="line"><span>  &quot;ide_state&quot;:</span><span>                 // IDE 状态</span></span>
<span class="line"><span>  &quot;max_tokens&quot;:</span><span>                // 最大 token</span></span>
<span class="line"><span>  &quot;idempotency_key&quot;:</span><span>           // 幂等键</span></span>
<span class="line"><span>  &quot;client_side_tool_v2_result&quot;</span><span> // 客户端工具结果</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div><h3 id="_2-3-已验证的可达端点" tabindex="-1">2.3 已验证的可达端点 <a class="header-anchor" href="#_2-3-已验证的可达端点" aria-label="Permalink to &quot;2.3 已验证的可达端点&quot;">​</a></h3><table tabindex="0"><thead><tr><th>端点</th><th>方法</th><th style="text-align:center;">状态</th><th>备注</th></tr></thead><tbody><tr><td><code>api2.cursor.sh/aiserver.v1.AuthService/GetEmail</code></td><td>POST JSON</td><td style="text-align:center;">✅ 200</td><td>需 Bearer token</td></tr><tr><td><code>api2.cursor.sh/aiserver.v1.DashboardService/GetCurrentPeriodUsage</code></td><td>POST JSON</td><td style="text-align:center;">✅ 200</td><td>需 Bearer token</td></tr><tr><td><code>api2.cursor.sh/aiserver.v1.DashboardService/GetPlanInfo</code></td><td>POST JSON</td><td style="text-align:center;">✅ 200</td><td>需 Bearer token</td></tr><tr><td><code>api2.cursor.sh/aiserver.v1.DashboardService/GetHardLimit</code></td><td>POST JSON</td><td style="text-align:center;">✅ 200</td><td>需 Bearer token</td></tr><tr><td><code>api2.cursor.sh/auth/full_stripe_profile</code></td><td>GET</td><td style="text-align:center;">✅ 200</td><td>需 Bearer token</td></tr><tr><td><code>api2.cursor.sh/auth/has_valid_payment_method</code></td><td>GET</td><td style="text-align:center;">✅ 200</td><td>需 Bearer token</td></tr><tr><td><code>api2.cursor.sh/aiserver.v1.AuthService/EmailValid</code></td><td>POST</td><td style="text-align:center;">❌ 401</td><td>Protobuf 端点需认证</td></tr></tbody></table><hr><h2 id="_3-登录认证协议" tabindex="-1">3. 登录认证协议 <a class="header-anchor" href="#_3-登录认证协议" aria-label="Permalink to &quot;3. 登录认证协议&quot;">​</a></h2><h3 id="_3-1-登录流程" tabindex="-1">3.1 登录流程 <a class="header-anchor" href="#_3-1-登录流程" aria-label="Permalink to &quot;3.1 登录流程&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 登录 URL:</span></span>
<span class="line"><span>   https://cursor.com/loginDeepControl</span></span>
<span class="line"><span>   ?challenge={base64url_sha256(verifier)}</span></span>
<span class="line"><span>   &amp;uuid={random_uuid}</span></span>
<span class="line"><span>   &amp;mode=login</span></span>
<span class="line"><span>   &amp;supportsSelectedTeamLogin=true</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 用户在浏览器完成 WorkOS 认证后，Cursor 后端保存 token</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 轮询获取 token (500ms 间隔):</span></span>
<span class="line"><span>   GET https://api2.cursor.sh/auth/poll?uuid={uuid}&amp;verifier={verifier}</span></span>
<span class="line"><span>   Headers:</span></span>
<span class="line"><span>     x-ghost-mode: false</span></span>
<span class="line"><span>     x-new-onboarding-completed: false</span></span>
<span class="line"><span>     x-cursor-client-version: 3.7.27</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>   ✅ 已验证返回:</span></span>
<span class="line"><span>   {</span></span>
<span class="line"><span>     &quot;accessToken&quot;: &quot;{JWT}&quot;,</span></span>
<span class="line"><span>     &quot;refreshToken&quot;: &quot;{JWT}&quot;,</span><span>     // 注意: 和 accessToken 相同</span></span>
<span class="line"><span>     &quot;authId&quot;: &quot;github|user_01J7...&quot;,</span></span>
<span class="line"><span>     &quot;challenge&quot;: &quot;{...}&quot;,</span></span>
<span class="line"><span>     &quot;uuid&quot;: &quot;{...}&quot;</span></span>
<span class="line"><span>   }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. JWT 格式:</span></span>
<span class="line"><span>   {</span></span>
<span class="line"><span>     &quot;sub&quot;: &quot;github|user_01J7...&quot;,</span></span>
<span class="line"><span>     &quot;exp&quot;: 1786505499,</span><span>         // 59 天过期</span></span>
<span class="line"><span>     &quot;iss&quot;: &quot;https://authentication.cursor.sh&quot;,</span></span>
<span class="line"><span>     &quot;scope&quot;: &quot;openid profile email offline_access&quot;,</span></span>
<span class="line"><span>     &quot;aud&quot;: &quot;https://cursor.com&quot;,</span></span>
<span class="line"><span>     &quot;type&quot;: &quot;session&quot;</span></span>
<span class="line"><span>   }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. 令牌刷新:</span></span>
<span class="line"><span>   POST https://api2.cursor.sh/oauth/token</span></span>
<span class="line"><span>   Content-Type: application/json</span></span>
<span class="line"><span>   Body: {</span></span>
<span class="line"><span>     &quot;grant_type&quot;: &quot;refresh_token&quot;,</span></span>
<span class="line"><span>     &quot;client_id&quot;: &quot;KbZUR41cY7W6zRSdpSUJ7I7mLYBKOCmB&quot;,</span></span>
<span class="line"><span>     &quot;refresh_token&quot;: &quot;{current_token}&quot;</span></span>
<span class="line"><span>   }</span></span>
<span class="line"><span>   ✅ 已验证: 返回 { access_token, shouldLogout }</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br><span class="line-number">33</span><br><span class="line-number">34</span><br><span class="line-number">35</span><br><span class="line-number">36</span><br><span class="line-number">37</span><br><span class="line-number">38</span><br><span class="line-number">39</span><br><span class="line-number">40</span><br><span class="line-number">41</span><br><span class="line-number">42</span><br><span class="line-number">43</span><br><span class="line-number">44</span><br></div></div><h3 id="_3-2-认证常量" tabindex="-1">3.2 认证常量 <a class="header-anchor" href="#_3-2-认证常量" aria-label="Permalink to &quot;3.2 认证常量&quot;">​</a></h3><div class="language-python vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">AUTH_CLIENT_ID</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;KbZUR41cY7W6zRSdpSUJ7I7mLYBKOCmB&quot;</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">AUTH_DOMAIN</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;authentication.cursor.sh&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 不是 prod.authentication!</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">WEBSITE_URL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;https://cursor.com&quot;</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">BACKEND_URL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;https://api2.cursor.sh&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><hr><h2 id="_4-已知但未验证的端点" tabindex="-1">4. 已知但未验证的端点 <a class="header-anchor" href="#_4-已知但未验证的端点" aria-label="Permalink to &quot;4. 已知但未验证的端点&quot;">​</a></h2><table tabindex="0"><thead><tr><th>端点</th><th>说明</th><th>未验证原因</th></tr></thead><tbody><tr><td><code>ChatService/StreamUnifiedChat</code></td><td>核心 AI 对话</td><td>需要 Protobuf 序列化</td></tr><tr><td><code>ChatService/StreamUnifiedChatWithTools</code></td><td>Agent 工具调用</td><td>同上</td></tr><tr><td><code>BidiService/streamBidi</code></td><td>双向流</td><td>需要 ConnectRPC 客户端库</td></tr><tr><td><code>AiService/serverTime</code></td><td>服务器时间</td><td>低优先级</td></tr><tr><td>CPU/Agent Service Runs</td><td>Agent 远程执行</td><td>需要 Protobuf 完整 schema</td></tr></tbody></table><hr><h2 id="_5-中转反向代理想法" tabindex="-1">5. 中转反向代理想法 <a class="header-anchor" href="#_5-中转反向代理想法" aria-label="Permalink to &quot;5. 中转反向代理想法&quot;">​</a></h2><h3 id="_5-1-可拦截的点" tabindex="-1">5.1 可拦截的点 <a class="header-anchor" href="#_5-1-可拦截的点" aria-label="Permalink to &quot;5.1 可拦截的点&quot;">​</a></h3><table tabindex="0"><thead><tr><th>拦截点</th><th style="text-align:center;">难度</th><th>说明</th></tr></thead><tbody><tr><td><strong>DNS: api2.cursor.sh → 代理 IP</strong></td><td style="text-align:center;">🔴 高</td><td>需要 HTTPS 证书</td></tr><tr><td><strong>登录 URL 的 redirect_uri</strong></td><td style="text-align:center;">🟢 低</td><td>可以劫持 cursor:// 协议</td></tr><tr><td><strong>auth/poll 返回后替换 token</strong></td><td style="text-align:center;">🟡 中</td><td>可以注入自己的 JWT</td></tr><tr><td><strong>ConnectRPC 代理</strong></td><td style="text-align:center;">🔴 高</td><td>需要实现 ConnectRPC 网关</td></tr><tr><td><strong>SSE 流拦截</strong></td><td style="text-align:center;">🟡 中</td><td>JSON 文本，可解析</td></tr></tbody></table><h3 id="_5-2-最简方案" tabindex="-1">5.2 最简方案 <a class="header-anchor" href="#_5-2-最简方案" aria-label="Permalink to &quot;5.2 最简方案&quot;">​</a></h3><p>托管自己的 <code>cursorvm-manager.com</code> 替代品，修改 Cursor 客户端的 provider 配置指向自己的端点，格式为 OpenAI 兼容 API。</p><hr><h2 id="_6-交付物" tabindex="-1">6. 交付物 <a class="header-anchor" href="#_6-交付物" aria-label="Permalink to &quot;6. 交付物&quot;">​</a></h2><table tabindex="0"><thead><tr><th>文件</th><th>说明</th></tr></thead><tbody><tr><td><code>scripts/cursor_auth.py</code></td><td>✅ 登录脚本（已验证）</td></tr><tr><td><code>scripts/cursor_login_catcher.py</code></td><td>✅ 登录捕获器</td></tr><tr><td><code>docs/07-authentication/auth-flow-analysis.md</code></td><td>✅ 认证流程</td></tr><tr><td><code>docs/07-authentication/auth-login-python-simulation.md</code></td><td>✅ Python 模拟指南</td></tr><tr><td><code>docs/05-communication-protocol/ai-communication-protocol.md</code></td><td>⚠️ 协议分析（需更新）</td></tr><tr><td>本文件</td><td>✅ 最终确定性报告</td></tr></tbody></table>`,36)])])}const b=a(r,[["render",p]]);export{h as __pageData,b as default};
